-- Enrichment marathon batch: Metasfresh, Metaview, Metricool, Metronome, Mezmo, Micro.blog, Microsoft 365, Microsoft Azure

-- ── Metasfresh ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Metasfresh is an open-source ERP system for small and mid-size manufacturing, trading, and distribution businesses, offering both self-hosted and paid cloud editions.$q$, short_description),
  pricing_model = COALESCE($q$Open Source (with paid cloud hosting and support tiers)$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted Community Edition); cloud hosting plans from around EUR 49 per user per month$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$Small software vendor (metas GmbH)$q$, company_size),
  headquarters = COALESCE($q$Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$Metasfresh Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Metasfresh review: an open-source ERP forked from ADempiere in 2015. See its features, cloud vs self-hosted pricing, pros, cons, and top alternatives for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Metasfresh is an open-source enterprise resource planning (ERP) system built for small and mid-size manufacturing, trading, and distribution companies. It was created by metas GmbH, a German software company founded by Mark Krake, Norbert Wessel, Tobias Schoeneberg, and Teodor Sarca, who had been early contributors to the ADempiere ERP project and founding members of the ADempiere Foundation. After years of extending and rewriting large parts of the ADempiere codebase for mid-market clients, the founders forked the project in 2015 and released the resulting software publicly as Metasfresh on October 6, 2015. The software is licensed under GPLv2, meaning the Community Edition source code can be used, modified, and distributed freely, with the full codebase hosted on GitHub. According to Open Hub statistics, Metasfresh is one of the most active open-source ERP projects worldwide. Architecturally, Metasfresh runs on a Java backend with a web-based user interface (metasfresh-webui) and a PostgreSQL database, and it can be deployed on-premise, self-hosted in a private cloud, or run through metas GmbH's managed cloud hosting. Core modules cover procurement, warehouse and inventory management, manufacturing (including bills of materials and production planning), sales and distribution, financial accounting, and customer relationship management, with configurable workflows aimed at process manufacturers, wholesalers, and distributors. Because there is no per-user software licensing fee for the self-hosted edition, businesses with in-house technical resources can run Metasfresh at a low direct software cost, paying only for infrastructure and optional support. metas GmbH also offers a managed cloud edition with support, priced per user per month, plus implementation services; independent estimates put typical implementation projects at two to six months and roughly EUR 20,000 to EUR 100,000 depending on scope and customization. Metasfresh's target audience is SMEs that need a flexible, customizable ERP without the licensing costs of platforms like SAP S/4HANA Cloud or NetSuite, and that are comfortable either self-hosting or working with metas GmbH's implementation partners. Its main competitors include other open-source or community-driven ERPs such as Odoo, ADempiere (its own ancestor project), and Apache OFBiz, as well as commercial mid-market ERPs like NetSuite, Odoo Enterprise, and SAP Business One. Metasfresh differentiates itself through its open-source licensing model, active developer community, deep ADempiere heritage (giving it mature accounting and distribution logic), and the option to avoid vendor lock-in entirely by self-hosting. The trade-off is that getting full value from the platform typically requires developer or ERP-consultant involvement, since the interface and configuration are less polished out of the box than fully commercial SaaS ERPs.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '590b2d7a-0185-4363-87ce-75d530896404';

