-- ── Metaview ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Metaview is an AI-powered interview intelligence platform that records, transcribes, and analyzes recruiting conversations to help hiring teams make faster, more consistent decisions.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free for up to 25 conversations per month; Pro from $50 per user per month (annual billing)$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Metaview Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Metaview review: AI interview intelligence for recruiting teams. See features, Free vs Pro vs Enterprise pricing, pros, cons, and alternatives for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Metaview is an AI-powered interview intelligence platform built for talent acquisition and recruiting teams. It was founded in 2018 by Siadhal Magos and Shahriar Tajbakhsh, former product and engineering leaders from Uber and Palantir, and the company is headquartered in London, United Kingdom. Metaview's core product records and transcribes interviews, then uses AI to generate structured notes, scorecards, and hiring-funnel reports, reducing the manual note-taking burden on interviewers and giving hiring teams consistent, searchable data about every candidate conversation. The product suite includes an AI Notetaker that automatically captures and structures interview notes, AI Reports for analyzing and optimizing the hiring funnel, an always-on AI Answers assistant that surfaces candidate information on demand, and AI Job Posts for generating job descriptions. Metaview has raised a total of roughly EUR 43 million (about USD 50 million) across multiple funding rounds, including a EUR 5.29 million round in December 2021 and a EUR 30 million (USD 35 million) Series B round announced in June 2025 that was led by GV (Google Ventures), with participation from Seedcamp, Plural, Vertex, Coelius Capital, and other investors. As of its Series B announcement, Metaview reported serving more than 2,500 companies, including Sony, Deel, Brex, Deliveroo, and ElevenLabs, and said its platform had captured and analyzed over 3 million interviews. Pricing follows a three-tier freemium model: a Free plan covering the core AI notetaker and transcription for up to 25 conversations per month; a Pro plan at $50 per user per month (billed annually, $60 month-to-month) with unlimited usage and enhanced features; and a custom-quoted Enterprise plan that adds SSO (SAML and OpenID Connect), SCIM provisioning, audit logs, custom data retention policies, a dedicated account manager, and custom integrations. Metaview's target audience is talent acquisition teams and recruiters at growing and enterprise companies who need to standardize interview quality, reduce interviewer bias, and speed up hiring-funnel analysis. Its main competitors in the interview intelligence and AI recruiting space include Aspect, BrightHire, HireVue, and general-purpose AI meeting notetakers like Otter.ai and Fireflies when used for recruiting. Metaview differentiates itself through its recruiting-specific AI agents, its backing by well-known enterprise investors including GV, and its focus on structuring interview data into actionable hiring-funnel insights rather than just producing transcripts.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '337159a2-d409-432a-86c7-1ec8ab203620';

