-- ── Metronome ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Metronome is a usage-based billing and monetization platform that helps software and AI companies price, meter, invoice, and report on consumption-based revenue.$q$, short_description),
  pricing_model = COALESCE($q$Custom / Enterprise (quote-based)$q$, pricing_model),
  starting_price = COALESCE($q$Custom pricing; contact sales for a quote$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Metronome Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Metronome review: the usage-based billing platform now owned by Stripe. See features, pricing model, customers like OpenAI and Anthropic, pros, cons and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Metronome is a usage-based billing and monetization platform for software and AI companies. It was founded in 2019 by Dropbox alumni Scott Woody and Kevin Liu and is headquartered in San Francisco, California. Metronome is a business infrastructure platform, not a music metronome app -- it helps companies meter product usage, define and iterate on usage-based or hybrid pricing plans, generate accurate invoices, and feed billing and revenue data into finance systems, all without engineering teams having to build custom billing logic in-house. The platform ingests usage events from a customer's product (API calls, compute time, tokens, seats, or any other billable metric), aggregates them against configurable pricing plans, and produces invoices, revenue reports, and real-time usage dashboards that both customers and internal teams can see. Metronome raised a Series A of $30 million in February 2022, a Series B of $43 million in 2024 led by NEA with participation from Andreessen Horowitz and General Catalyst, and a Series C of $50 million in February 2025, at which point the company was valued at $470 million; total funding reached roughly $128 million prior to acquisition. In December 2025, Stripe announced a definitive agreement to acquire Metronome, and the acquisition closed on January 14, 2026, in a deal reported at approximately $1 billion -- roughly double Metronome's prior valuation. Stripe CEO Patrick Collison framed the acquisition around the rise of metered, usage-based pricing as the dominant business model for AI-era software companies, saying the shift in how businesses generate revenue would be as significant as the advent of SaaS itself. Metronome's customer base includes major AI labs and infrastructure companies such as OpenAI, Anthropic, Databricks, Confluent, and Nvidia, reflecting strong adoption among companies that charge based on API usage, compute consumption, or tokens rather than flat per-seat subscriptions. Metronome does not publish self-serve pricing; prospective customers must contact sales for a custom quote based on their billing volume and complexity. Its target audience is B2B software and AI companies, particularly those with complex, usage-based, or hybrid pricing models that outgrow simple subscription billing tools. Competitors and adjacent tools include Stripe Billing itself (with which Metronome is now being integrated), Orb, Chargebee, Zuora, and Maxio. Metronome differentiates itself through its purpose-built focus on usage-based and consumption pricing at enterprise scale, its strong foothold among leading AI companies, and -- following the Stripe acquisition -- deeper integration with Stripe's broader payments and billing ecosystem going forward.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3979638f-c194-4be0-8b95-c01a647146b8';

